sql:
SELECT AVG(points) AS AvgPoints
FROM player_game_stats
WHERE player_id = (SELECT player_id FROM players WHERE player_name = 'A.J. Bouye');

external_knowledge:
- 'Tight ends' are players whose primary position is 'TE'.;
- 'Nursing wounds' is a metaphorical way of saying that they are injured.;
- 'Dallas Cowboys' is the team name used to identify the specific team the players are associated with.

sql:
SELECT players.player_name
FROM players
INNER JOIN player_game_stats ON players.player_id = player_game_stats.player_id
WHERE player_game_stats.points = (
    SELECT MAX(points) FROM player_game_stats
);

SELECT player_id, player_name
FROM players
WHERE player_id NOT IN (
    SELECT player_id
    FROM player_game_stats
);

external_knowledge:
- 'captains steering their ships' is a metaphor for quarterbacks (QB) leading their teams;
- 'navigating the seas of fortune' symbolizes having high-value contracts;
- 'on the roster' implies being listed in the team's official player list.

sql:
SELECT DISTINCT p.player_name, p.nationality
FROM players p
JOIN awards a ON p.player_id = a.player_id;

external_knowledge:
- "stars" refers to the players;
- "golden fleet" is a metaphor for the team;
- "sails under the banner" signifies playing for the team;
- "treasure chests filled beyond fifty million" means the contract value is more than $50,000,000;
- "national origins" refers to the player's nationality.

sql:
SELECT players.player_name, awards.award_name
FROM players
INNER JOIN awards ON players.player_id = awards.player_id;
